// searchTabClass returns the active/inactive class string for a search tab.
// Kept in Go (not inlined in the templ) so the active-tab logic is one
// canonical place — same shape as the legacy template's
// `{{if eq $k $b.Kind}} active{{end}}` block.
func searchTabClass(kind, active string) string {
	if kind == active {
		return "search-tab active"
	}
	return "search-tab"
}

